layui.use(["laydate","table","util","form"],function(){let form=layui.form;let table=layui.table;let util=layui.util;table.render({elem:".layui-table",id:"blogTable",height:450,url:"/blog/listBlogPage",page:true,method:"get",toolbar:true,defaultToolbar:["filter","print","exports"],request:{pageName:"page",limitName:"count"},parseData:function(a){return{status:a.status,count:a.fields.totalCount,message:a.message,data:a.data}},response:{statusName:"status",statusCode:200,msgName:"message",countName:"count",dataName:"data"},cols:[[{type:"checkbox",fixed:"left"},{field:"id",title:"ID",width:80,sort:true},{field:"title",title:"标题",width:230},{field:"author",title:"作者",width:80,sort:true},{field:"type",title:"分类",width:80},{field:"createTime",title:"创建时间",width:170,templet:function(a){return util.toDateString(a.createTime,"yyyy-MM-dd HH:ss")}},{field:"modifyTime",title:"最后修改时间",width:170,sort:true,templet:function(a){return util.toDateString(a.modifyTime,"yyyy-MM-dd HH:ss")}},{field:"status",title:"状态",width:80,sort:true,templet:function(a){if(a.status===1){return"正常"}else{if(a.status===0){return"已删除"}}}},{field:"comment",title:"评论数",width:80},{field:"view",title:"浏览量",width:90,sort:true},{title:"操作",fixed:"right",width:180,align:"left",toolbar:"#toolbar"}]]});$.ajax({url:"/blog_type",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200){$.each(a.data,function(b,c){$("#type").append(new Option(c.name,c.name))});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(search)",function(a){let searchDTO=a.field;table.reload("blogTable",{url:"/blog/search",where:{title:searchDTO.title,type:searchDTO.type,author:searchDTO.author},method:"POST",parseData:function(b){return{status:b.status,count:b.fields.totalCount,message:b.message,data:b.data}},response:{statusName:"status",statusCode:200,msgName:"message",countName:"count",dataName:"data"}});return false});table.on("tool(blog)",function(a){let layEvent=a.event;let data=a.data;if(layEvent==="restore"){if(data.status===1){layer.msg("不能恢复正常的项！",{icon:2})}else{layer.confirm("确认恢复此博客？",{btn:["确认","取消"]},function(b){$.ajax({url:"/blog/restore/"+data.id,method:"PUT",dataType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)})}}else{if(layEvent==="edit"){window.parent.xadmin.add_tab(data.title,"/admin/blog-detail?blogId="+data.id+"&token="+localStorage.getItem("token"))}else{if(layEvent==="delete"){if(data.status===0){layer.msg("不能删除已经删除的项！",{icon:2})}else{layer.confirm("确认删除此博客？",{btn:["确认","取消"]},function(b){$.ajax({url:"/blog/"+data.id,method:"DELETE",dataType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)})}}}}})});